**Código 3 - Plugin Minecraft Java (Spigot/Paper):**
```java
package com.tuplugin;
import org.bukkit.plugin.java.JavaPlugin;
import org.bukkit.command.Command;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

public class MiPlugin extends JavaPlugin {
    @Override
    public void onEnable() {
        getLogger().info("¡Plugin activado con éxito! 🎮");
    }

    @Override
    public boolean onCommand(CommandSender sender, Command cmd, String label, String[] args) {
        if(cmd.getName().equalsIgnoreCase("hola")) {
            if(sender instanceof Player) {
                Player p = (Player) sender;
                p.sendMessage("¡Hola " + p.getName() + "! Bienvenido 🚀");
            }
            return true;
        }
        return false;
    }
}
```
